celery_app.conf.update(task_serializer='json', accept_content=['json'], result_serializer='json', timezone='UTC', enable_utc=True, task_track_started=True, task_time_limit=30 * 60, task_soft_time_limit=25 * 60, worker_prefetch_multiplier=1, worker_max_tasks_per_child=1000, task_routes={'app.tasks.reports.*': {'queue': 'reports'}, 'app.tasks.ml_batch.*': {'queue': 'ml_batch'}, 'app.tasks.media.*': {'queue': 'media'}, 'app.tasks.analytics.*': {'queue': 'analytics'}, 'app.tasks.notifications.*': {'queue': 'notifications'}}, task_default_retry_delay=60, task_max_retries=3, beat_schedule={'refresh-materialized-views': {'task': 'app.tasks.analytics.refresh_materialized_views', 'schedule': crontab(minute=0)}, 'cleanup-stale-sessions': {'task': 'app.tasks.analytics.cleanup_stale_sessions', 'schedule': crontab(minute=30)}, 'compute-company-benchmarks': {'task': 'app.tasks.ml_batch.compute_company_benchmarks', 'schedule': crontab(hour=2, minute=0)}, 'aggregate-cohort-analytics': {'task': 'app.tasks.analytics.aggregate_cohort_analytics', 'schedule': crontab(hour=2, minute=15)}, 'cleanup-expired-data': {'task': 'app.tasks.analytics.cleanup_expired_data', 'schedule': crontab(hour=2, minute=30)}, 'purge-old-emotional-data': {'task': 'app.tasks.analytics.purge_old_emotional_data', 'schedule': crontab(hour=2, minute=45)}, 'generate-weekly-digests': {'task': 'app.tasks.notifications.generate_weekly_digests_all_users', 'schedule': crontab(hour=3, minute=0, day_of_week=0)}, 'evaluate-model-drift': {'task': 'app.tasks.ml_batch.evaluate_model_drift', 'schedule': crontab(hour=3, minute=30, day_of_week=0)}, 'retrain-deberta-check': {'task': 'app.tasks.ml_batch.retrain_deberta_if_needed', 'schedule': crontab(hour=4, minute=0, day_of_month=1)}})